{"call_id":"call_rrd15rNBt6Pz7iHeixpArFGL","turn_id":"019db179-a3fa-7b43-b225-5ffee4147aed","command":["C:\Program Files\PowerShell\7\pwsh.exe","-Command","Get-Content lib\views\home\contact_tracker_screen.dart"],"cwd":"C:\Users\onlin\.openclaw\workspace\temp-builder","parsed_cmd":[{"type":"unknown","cmd":"Get-Content lib\views\home\contact_tracker_screen.dart"}],"source":"agent","stdout":"import 'package:flutter/material.dart';
import '../../core/services/contact_tracker_service.dart';
import '../../core/services/screen_persistence.dart';
import '../../models/contact.dart';

/// Contact Tracker screen — manage contacts, log interactions,
/// track follow-ups, and view network health.
class ContactTrackerScreen extends StatefulWidget {
  const ContactTrackerScreen({super.key});

  @override
  State<ContactTrackerScreen> createState() => _ContactTrackerScreenState();
}

class _ContactTrackerScreenState extends State<ContactTrackerScreen>
    with SingleTickerProviderStateMixin {
  final ContactTrackerService _service = ContactTrackerService();
  final _persistence = ScreenPersistence<Contact>(
    storageKey: 'contact_tracker_entries',
    toJson: (e) => e.toJson(),
    fromJson: Contact.fromJson,
  );
  late TabController _tabController;
  final TextEditingController _searchController = TextEditingController();
  String _searchQuery = '';
  RelationshipCategory? _categoryFilter;

  @override
  void initState() {
    super.initState();
    _tabController = TabController(length: 3, vsync: this);
    _searchController.addListener(() {
      setState(() => _searchQuery = _searchController.text.trim());
    });
    _loadData();
  }

  Future<void> _loadData() async {
    final saved = await _persistence.load();
    for (final contact in saved) {
      _service.addContact(contact);
    }
    if (saved.isNotEmpty && mounted) setState(() {});
  }

  Future<void> _save() async {
    await _persistence.save(_service.contacts);
  }

  @override
  void dispose() {
    _tabController.dispose();
    _searchController.dispose();
    super.dispose();
  }

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(
        title: const Text('Contact Tracker'),
        elevation: 0,
        bottom: TabBar(
          controller: _tabController,
          tabs: const [
            Tab(icon: Icon(Icons.people), text: 'Contacts'),
            Tab(icon: Icon(Icons.notifications_active), text: 'Follow-ups'),
            Tab(icon: Icon(Icons.health_and_safety), text: 'Health'),
          ],
        ),
      ),
      body: TabBarView(
        controller: _tabController,
        children: [
          _ContactsTab(
            service: _service,
            searchController: _searchController,
            searchQuery: _searchQuery,
            categoryFilter: _categoryFilter,
            onCategoryChanged: (c) => setState(() => _categoryFilter = c),
            onChanged: () { setState(() {}); _save(); },
          ),
          _FollowUpsTab(service: _service, onChanged: () { setState(() {}); _save(); }),
          _HealthTab(service: _service),
        ],
      ),
      floatingActionButton: FloatingActionButton.extended(
        onPressed: () => _showAddContactDialog(),
        icon: const Icon(Icons.person_add),
        label: const Text('Add Contact'),
      ),
    );
  }

  Future<void> _showAddContactDialog() async {
    final result = await showDialog<bool>(
      context: context,
      builder: (ctx) => _AddContactDialog(service: _service),
    );
    if (result == true) {
      if (!mounted) return;
      setState(() {});
      _save();
    }
  }
}

