                          : t.trend == 'decreasing'
                              ? Icons.trending_down
                              : Icons.trending_flat,
                      size: 18,
                      color: t.trend == 'increasing'
                          ? Colors.green
                          : t.trend == 'decreasing'
                              ? Colors.red
                              : Colors.grey,
