                  fontSize: 16, fontWeight: FontWeight.bold),
            ),
            const SizedBox(height: 8),
            if (contact.interactions.isEmpty)
              Padding(
                padding: const EdgeInsets.all(16),
                child: Text('No interactions logged yet',
                    style: TextStyle(color: Colors.grey[400])),
              )
            else
              ...contact.interactions.reversed.take(20).map((i) => Padding(
                    padding: const EdgeInsets.only(bottom: 6),
                    child: Row(
                      crossAxisAlignment: CrossAxisAlignment.start,
                      children: [
                        Icon(Icons.circle, size: 8, color: Colors.blue[300]),
                        const SizedBox(width: 8),
                        Expanded(
                          child: Column(
                            crossAxisAlignment: CrossAxisAlignment.start,
                            children: [
                              Text(
                                '${i.date.month}/${i.date.day}/${i.date.year} · ${i.method.label}',
                                style: TextStyle(
                                    fontSize: 12,
                                    color: Colors.grey[500]),
                              ),
                              if (i.note.isNotEmpty)
                                Text(i.note,
                                    style:
                                        const TextStyle(fontSize: 14)),
                            ],
                          ),
                        ),
                      ],
                    ),
                  )),

            const SizedBox(height: 16),

            // Actions
            Row(
              children: [
                Expanded(
                  child: OutlinedButton.icon(
                    onPressed: () {
                      service.archiveContact(contact.id);
                      onChanged();
                      Navigator.of(context).pop();
                    },
                    icon: const Icon(Icons.archive),
                    label: const Text('Archive'),
                  ),
                ),
                const SizedBox(width: 8),
                Expanded(
                  child: FilledButton.icon(
                    onPressed: () {
                      showDialog(
                        context: context,
                        builder: (ctx) => _LogInteractionDialog(
                          service: service,
                          contact: contact,
                        ),
                      ).then((result) {
                        if (result == true) {
                          onChanged();
                          Navigator.of(context).pop();
                        }
                      });
                    },
                    icon: const Icon(Icons.add_comment),
                    label: const Text('Log Interaction'),
                  ),
                ),
              ],
            ),
          ],
        ),
      ),
    );
  }
}

class _InfoChip extends StatelessWidget {
  final IconData icon;
  final String label;
  final Color color;

  const _InfoChip(
      {required this.icon, required this.label, required this.color});

  @override
  Widget build(BuildContext context) {
    return Container(
      padding: const EdgeInsets.symmetric(horizontal: 10, vertical: 6),
      decoration: BoxDecoration(
        color: color.withAlpha(20),
        borderRadius: BorderRadius.circular(8),
        border: Border.all(color: color.withAlpha(60)),
      ),
      child: Row(
        mainAxisSize: MainAxisSize.min,
        children: [
          Icon(icon, size: 14, color: color),
          const SizedBox(width: 4),
          Text(label,
              style: TextStyle(
                  fontSize: 12, color: color, fontWeight: FontWeight.w600)),
        ],
      ),
    );
  }
}

