    if (health.categoryBreakdown.isNotEmpty) {
      buf.writeln('\nBy Category:');
      for (final cs in health.categoryBreakdown) {
        buf.writeln(
            '  ${cs.category.emoji} ${cs.category.label}: ${cs.count} contacts');
      }
    }

    return buf.toString();
  }
}
